const backendBase = process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:3000";

export async function fetchBackendConfig() {
  try {
    const response = await fetch(`${backendBase}/api/config`, { cache: "no-store" });
    if (!response.ok) return { ok: false, status: response.status, data: null };
    const data = await response.json();
    return { ok: true, status: response.status, data };
  } catch (_error) {
    return { ok: false, status: 0, data: null };
  }
}

export function getLegacyBaseUrl() {
  return process.env.NEXT_PUBLIC_LEGACY_BASE_URL || "http://localhost:3000";
}
