import { fetchBackendConfig, getLegacyBaseUrl } from "../lib/api";

const headerStyle = {
  width: "100%",
  padding: "20px 30px",
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  background: "rgba(13, 27, 42, 0.95)",
  borderBottom: "1px solid rgba(65, 90, 119, 0.3)"
};

const buttonStyle = {
  display: "inline-block",
  padding: "10px 18px",
  borderRadius: "10px",
  border: "1px solid rgba(255,255,255,0.25)",
  marginLeft: "10px",
  fontWeight: 600
};

export default async function HomePage() {
  const config = await fetchBackendConfig();
  const legacyBase = getLegacyBaseUrl();

  return (
    <>
      <header style={headerStyle}>
        <strong style={{ fontSize: "1.2rem" }}>E-BPHTB Next</strong>
        <nav>
          <a style={buttonStyle} href={`${legacyBase}/login.html`}>
            Masuk
          </a>
          <a style={buttonStyle} href={`${legacyBase}/registrasi.html?verse=wp`}>
            Registrasi WP
          </a>
          <a style={buttonStyle} href={`${legacyBase}/registrasi.html?verse=karyawan`}>
            Registrasi Karyawan
          </a>
          <a style={buttonStyle} href={`${legacyBase}/registrasi.html?verse=pu`}>
            Registrasi PPAT/PPATS
          </a>
        </nav>
      </header>

      <main className="container" style={{ paddingTop: 48, paddingBottom: 48 }}>
        <h1 style={{ marginTop: 0 }}>Selamat Datang di E-BPHTB Kabupaten Bogor</h1>
        <p style={{ lineHeight: 1.7, maxWidth: 760 }}>
          Ini adalah halaman hasil migrasi awal dari <code>halaman_awal.html</code> ke Next.js.
          Halaman lain tetap berjalan di sistem lama agar transisi aman.
        </p>

        <section
          style={{
            marginTop: 24,
            padding: 16,
            borderRadius: 12,
            border: "1px solid rgba(255,255,255,0.2)",
            background: "rgba(255,255,255,0.06)"
          }}
        >
          <h2 style={{ marginTop: 0 }}>Koneksi Backend Lama</h2>
          <p style={{ marginBottom: 8 }}>
            Target API: <code>{process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:3000"}</code>
          </p>
          <p style={{ margin: 0 }}>
            Status: {config.ok ? <strong>Terhubung</strong> : <strong>Tidak terhubung</strong>}
          </p>
        </section>

        <section style={{ marginTop: 24 }}>
          <a style={{ ...buttonStyle, marginLeft: 0 }} href={`${legacyBase}/public-validasi-qr.html`}>
            Cek Keaslian Dokumen (Legacy)
          </a>
        </section>
      </main>
    </>
  );
}
